import axios from 'axios';

const API_BASE = 'http://localhost:8080/area-backend/api';

const api = axios.create({
  baseURL: API_BASE,
  headers: {
    'Content-Type': 'application/json'
  }
});

api.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  console.log('🔄 Interceptor: token found?', !!token);
  console.log('🔄 Token value:', token);

  if (token) {
    // Пробуем разные форматы заголовка
    config.headers.Authorization = token;  // Просто токен
    // ИЛИ
    // config.headers.Authorization = `Bearer ${token}`;  // С префиксом Bearer
    // ИЛИ
    // config.headers['X-Auth-Token'] = token;  // Кастомный заголовок

    console.log('🔄 Установлен заголовок Authorization:', config.headers.Authorization);
  } else {
    console.warn('⚠️ Token not found in localStorage');
  }

  return config;
});

export const authAPI = {
  login: async (username, password) => {  // ← ИСПРАВЬТЕ: llogin → login!
    try {
      const body = { username, password };
      const response = await api.post('/login', body);

      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('username', response.data.username);
        return { success: true, data: response.data };
      }
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка авторизации'
      };
    }
  },

  logout: async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        await api.post('/logout', {}, {
          headers: { Authorization: token }
        });
      } catch (error) {
        console.log('Logout completed (ignoring errors)');
      }
    }
    localStorage.removeItem('token');
    localStorage.removeItem('username');
  }
};  // ← ВОТ ОНА! ПРОПУЩЕНА ЗАКРЫВАЮЩАЯ СКОБКА И ТОЧКА С ЗАПЯТОЙ!

export const pointAPI = {
  checkPoint: async (x, y, r) => {
    try {
      const body = { x, y, r };
      const response = await api.post('/check', body);
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка проверки точки'
      };
    }
  },

  getResults: async () => {
    try {
      const response = await api.get('/results');
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка загрузки результатов'
      };
    }
  },

  clearResults: async () => {
    try {
      await api.delete('/results');
      return { success: true };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка очистки'
      };
    }
  }
};

export const checkAuth = async () => {
  const token = localStorage.getItem('token');
  if (!token) return false;

  try {
    const response = await api.get('/results');
    return response.status === 200;
  } catch {
    return false;
  }
};

export default api;
